// Generated by GitHub Copilot (Claude Sonnet 4.6)
// Validates a planned Vultr API call against the openapi.json contract before execution.
// Checks method, path, required parameters, and request body schema.
// Usage: node validate-api-call.js --method <METHOD> --path <PATH> [--query <JSON>] [--body <JSON>] [--spec <PATH>]

/* eslint-env node */
/* global require, process, __dirname, console */
'use strict';

const fs = require('fs');
const path = require('path');

// ---------------------------------------------------------------------------
// CLI argument parser
// ---------------------------------------------------------------------------
function parseArgs(argv) {
  const args = {};
  for (let i = 2; i < argv.length; i++) {
    if (argv[i].startsWith('--') && i + 1 < argv.length && !argv[i + 1].startsWith('--')) {
      args[argv[i].slice(2)] = argv[i + 1];
      i++;
    }
  }
  return args;
}

// ---------------------------------------------------------------------------
// Spec loader
// ---------------------------------------------------------------------------
function loadSpec(specPath) {
  const resolved = path.resolve(specPath);
  if (!fs.existsSync(resolved)) {
    console.error(`ERROR: OpenAPI spec not found: ${resolved}`);
    process.exit(2);
  }
  try {
    return JSON.parse(fs.readFileSync(resolved, 'utf8'));
  } catch (err) {
    console.error(`ERROR: Failed to parse spec JSON: ${err.message}`);
    process.exit(2);
  }
}

// ---------------------------------------------------------------------------
// $ref resolver (supports local #/ refs only)
// ---------------------------------------------------------------------------
function resolveRef(spec, ref) {
  if (typeof ref !== 'string' || !ref.startsWith('#/')) {
    return null;
  }
  const parts = ref.slice(2).split('/');
  let cursor = spec;
  for (const part of parts) {
    const key = decodeURIComponent(part.replace(/~1/g, '/').replace(/~0/g, '~'));
    if (cursor == null || typeof cursor !== 'object' || !(key in cursor)) {
      return null;
    }
    cursor = cursor[key];
  }
  return cursor;
}

// Fully resolve a schema, following any top-level $ref.
function resolveSchema(spec, schema) {
  if (!schema) return null;
  if (schema.$ref) {
    return resolveRef(spec, schema.$ref);
  }
  return schema;
}

// ---------------------------------------------------------------------------
// Path matching: /instances/{instance-id} matches /instances/abc123
// ---------------------------------------------------------------------------
function matchPath(specPath, requestPath) {
  const pattern = specPath.replace(/\{[^}]+\}/g, '[^/]+');
  return new RegExp(`^${pattern}$`).test(requestPath);
}

// ---------------------------------------------------------------------------
// Extract path parameter values from a concrete request path
// ---------------------------------------------------------------------------
function extractPathParams(specPath, requestPath) {
  const names = [];
  const pattern = specPath.replace(/\{([^}]+)\}/g, (_, name) => {
    names.push(name);
    return '([^/]+)';
  });
  const m = requestPath.match(new RegExp(`^${pattern}$`));
  if (!m) return {};
  return Object.fromEntries(names.map((n, i) => [n, m[i + 1]]));
}

// ---------------------------------------------------------------------------
// Minimal JSON Schema validator (handles type, required, properties, enum)
// ---------------------------------------------------------------------------
function validateSchema(spec, rawSchema, value, location) {
  const errors = [];
  const schema = resolveSchema(spec, rawSchema);
  if (!schema) return errors;

  // allOf: validate each sub-schema
  if (Array.isArray(schema.allOf)) {
    for (const sub of schema.allOf) {
      errors.push(...validateSchema(spec, sub, value, location));
    }
    return errors;
  }

  const isObject = typeof value === 'object' && value !== null && !Array.isArray(value);

  if (schema.type === 'object' || schema.properties || schema.required) {
    if (!isObject) {
      errors.push(`${location}: expected object, got ${Array.isArray(value) ? 'array' : typeof value}`);
      return errors;
    }
    for (const req of schema.required || []) {
      if (!(req in value)) {
        errors.push(`${location}.${req}: required field is missing`);
      }
    }
    for (const [key, val] of Object.entries(value)) {
      if (schema.properties && key in schema.properties) {
        errors.push(...validateSchema(spec, schema.properties[key], val, `${location}.${key}`));
      }
      // additionalProperties: false enforcement is intentionally skipped to avoid
      // false positives from extension fields common in Vultr payloads.
    }
  } else if (schema.type === 'array') {
    if (!Array.isArray(value)) {
      errors.push(`${location}: expected array, got ${typeof value}`);
    } else if (schema.items) {
      value.forEach((item, idx) => {
        errors.push(...validateSchema(spec, schema.items, item, `${location}[${idx}]`));
      });
    }
  } else if (schema.type) {
    const actualType = typeof value;
    const typeMap = {
      string: 'string',
      boolean: 'boolean',
      number: 'number',
      integer: 'number'
    };
    const expected = typeMap[schema.type];
    if (expected && actualType !== expected) {
      // integer allows whole-number JS numbers
      if (!(schema.type === 'integer' && Number.isInteger(value))) {
        errors.push(`${location}: expected ${schema.type}, got ${actualType}`);
      }
    }
  }

  if (schema.enum !== undefined && !schema.enum.includes(value)) {
    errors.push(`${location}: "${value}" is not one of [${schema.enum.join(', ')}]`);
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Core validation logic
// ---------------------------------------------------------------------------
function validate(spec, method, requestPath, queryParams, body) {
  const errors = [];
  const warnings = [];

  // --- Find the matching operation ---
  let matchedOp = null;
  let matchedSpecPath = null;

  const normalizedMethod = method.toLowerCase();
  const validMethods = ['get', 'post', 'put', 'patch', 'delete', 'head', 'options'];

  if (!validMethods.includes(normalizedMethod)) {
    errors.push(`Unknown HTTP method: ${method}`);
    return { errors, warnings };
  }

  for (const [specPath, pathItem] of Object.entries(spec.paths || {})) {
    if (matchPath(specPath, requestPath)) {
      const op = pathItem[normalizedMethod];
      if (op) {
        matchedOp = op;
        matchedSpecPath = specPath;
        break;
      }
    }
  }

  if (!matchedOp) {
    errors.push(`No operation found for ${method.toUpperCase()} ${requestPath}`);
    return { errors, warnings };
  }

  const pathParams = extractPathParams(matchedSpecPath, requestPath);

  // --- Validate parameters ---
  const allParams = [
    ...(spec.paths[matchedSpecPath].parameters || []),
    ...(matchedOp.parameters || []),
  ];

  for (const rawParam of allParams) {
    const param = rawParam.$ref ? resolveRef(spec, rawParam.$ref) || rawParam : rawParam;
    if (!param.required) continue;

    if (param.in === 'path' && !(param.name in pathParams)) {
      errors.push(`Missing required path parameter: ${param.name}`);
    }
    if (param.in === 'query' && !(param.name in (queryParams || {}))) {
      errors.push(`Missing required query parameter: ${param.name}`);
    }
    if (param.in === 'header' && param.name.toLowerCase() !== 'authorization') {
      // Only surface non-auth required headers as errors; auth is handled separately.
      errors.push(`Missing required header: ${param.name}`);
    }
  }

  // --- Validate request body ---
  if (matchedOp.requestBody) {
    const rawReqBody = matchedOp.requestBody.$ref
      ? resolveRef(spec, matchedOp.requestBody.$ref)
      : matchedOp.requestBody;

    if (rawReqBody && rawReqBody.required && (body == null || Object.keys(body).length === 0)) {
      errors.push('Request body is required but was not provided');
    }

    if (body != null) {
      const jsonContent = rawReqBody?.content?.['application/json'];
      if (jsonContent?.schema) {
        errors.push(...validateSchema(spec, jsonContent.schema, body, 'body'));
      }
    }
  } else if (body != null && Object.keys(body).length > 0) {
    warnings.push('Request body provided but this operation does not declare a requestBody');
  }

  // --- Security advisory ---
  if (!matchedOp.security || matchedOp.security.length === 0) {
    warnings.push('This operation has no explicit security requirement in the spec');
  }

  return {
    errors,
    warnings,
    operationId: matchedOp.operationId || '(no operationId)',
    specPath: matchedSpecPath,
    method: method.toUpperCase(),
  };
}

// ---------------------------------------------------------------------------
// Entry point
// ---------------------------------------------------------------------------
function main() {
  const args = parseArgs(process.argv);

  if (!args.method || !args.path) {
    console.error(
      'Usage: node validate-api-call.js --method <METHOD> --path <PATH> [--query <JSON>] [--body <JSON>] [--spec <PATH>]'
    );
    console.error('');
    console.error('Examples:');
    console.error('  node validate-api-call.js --method GET --path /instances');
    console.error('  node validate-api-call.js --method POST --path /instances --body \'{"region":"ewr","plan":"vc2-1c-1gb","os_id":387}\'');
    process.exit(2);
  }

  const specPath = args.spec || path.join(__dirname, '../../../openapi.json');

  let queryParams = {};
  if (args.query) {
    try {
      queryParams = JSON.parse(args.query);
    } catch {
      console.error('ERROR: --query must be valid JSON (e.g. \'{"per_page":"25"}\')');
      process.exit(2);
    }
  }

  let body = null;
  if (args.body) {
    try {
      body = JSON.parse(args.body);
    } catch {
      console.error('ERROR: --body must be valid JSON');
      process.exit(2);
    }
  }

  const spec = loadSpec(specPath);
  const result = validate(spec, args.method, args.path, queryParams, body);

  // --- Report ---
  if (result.operationId) {
    console.log(`Operation : ${result.operationId}`);
    console.log(`Matched   : ${result.method} ${result.specPath}`);
  }

  for (const w of result.warnings || []) {
    console.log(`WARN : ${w}`);
  }

  if (result.errors.length > 0) {
    for (const e of result.errors) {
      console.error(`ERROR: ${e}`);
    }
    process.exit(1);
  }

  console.log('Validation passed.');
  process.exit(0);
}

main();
